def solve(chars: List[str]) -> int:
    i = 0
    res = 0
    while i < len(chars):
        group_length = 1
        while i + group_length < len(chars) and chars[i + group_length] == chars[i]:
            group_length += 1
        chars[res] = chars[i]
        res += 1
        if group_length > 1:
            for c in str(group_length):
                chars[res] = c
                res += 1
        i += group_length
    return res

